class Solution:
    def judgePoint24(self, cards):
        import itertools
        def solve(nums):
            if len(nums) == 1:
                return abs(nums[0] - 24) < 1e-6
            n = len(nums)
            for i in range(n):
                for j in range(n):
                    if i == j:
                        continue
                    rest = [nums[t] for t in range(n) if t != i and t != j]
                    a, b = nums[i], nums[j]
                    cands = [a + b, a - b, a * b]
                    if abs(b) > 1e-9:
                        cands.append(a / b)
                    for c in cands:
                        if solve(rest + [c]):
                            return True
            return False
        return solve([float(x) for x in cards])

