var judgePoint24 = function(cards) {
    const EPS = 1e-6;
    const dfs = (nums) => {
        if (nums.length === 1) return Math.abs(nums[0] - 24) < EPS;
        const n = nums.length;
        for (let i = 0; i < n; i++) {
            for (let j = 0; j < n; j++) {
                if (i === j) continue;
                const rest = [];
                for (let t = 0; t < n; t++) if (t !== i && t !== j) rest.push(nums[t]);
                const a = nums[i], b = nums[j];
                const results = [a + b, a * b, a - b];
                if (Math.abs(b) > 1e-9) results.push(a / b);
                for (const r of results) {
                    if (dfs(rest.concat([r]))) return true;
                }
            }
        }
        return false;
    };
    return dfs(cards.map(Number));
};
